	sessionId: string;
	projectPath: string;
	repository?: string;
	gitBranch?: string;
	gitSha?: string;
	tag?: SessionTag;
	content: string;
	subagents?: SubagentFile[];
}

export interface UploadResult {
	success: boolean;
	status?: number;
	error?: string;
}

export const DEFAULT_ENDPOINT =
	"https://flick-api.numia.workers.dev/api/orpc/compound";

