166→		};
167→
168→		// ClickHouse Cloud can silently drop inserts under load.
169→		// Retry the insert+read cycle to handle transient failures.
170→		let results: Awaited<ReturnType<typeof waitForRow>> = [];
171→		for (let attempt = 0; attempt < 3; attempt++) {
172→			await ingestSession(executor, input, {
173→				userId: "test_user",
