250→// Helpers that operate on a specific config dir (matching the RUDEL_CONFIG_DIR env var)
251→function saveCredentialsToDir(
252→	dir: string,
253→	token: string,
254→	apiBaseUrl: string,
255→): void {
256→	const { writeFileSync } = require("node:fs");
257→	writeFileSync(
258→		join(dir, "credentials.json"),
259→		JSON.stringify({ token, apiBaseUrl }, null, 2),
260→		{ mode: 0o600 },
261→	);
262→}
263→
264→function loadCredentialsFromDir(
265→	dir: string,
266→): { token: string; apiBaseUrl: string } | null {
267→	const path = join(dir, "credentials.json");
268→	try {
269→		const { readFileSync } = require("node:fs");
270→		const content = readFileSync(path, "utf-8");
271→		return JSON.parse(content);
272→	} catch {
273→		return null;
274→	}
275→}
276→
277→function clearCredentialsFromDir(dir: string): void {
278→	const path = join(dir, "credentials.json");
279→	try {
280→		const { rmSync } = require("node:fs");
281→		rmSync(path);
282→	} catch {
283→		// already gone
284→	}
285→}
